mapper.select:
SELECT l.LOCATION_ID, l.ZONE_ID, l.LOCATION_CD, l.LOCATION_NM, l.MAX_CAPACITY, l.CURRENT_USAGE, l.LOCATION_STATUS, l.USE_YN, l.REG_USER_ID, l.REG_DTM, l.UPD_USER_ID, l.UPD_DTM, z.PLANT_CD, p.PLANT_NM, z.WAREHOUSE_CD, w.WAREHOUSE_NM, z.ZONE_CD, z.ZONE_NM, c.COM_NM AS LOCATION_STATUS_NM FROM MCS_LOCATION l INNER JOIN MCS_ZONE z ON l.ZONE_ID = z.ZONE_ID INNER JOIN MST_PLANT p ON z.PLANT_CD = p.PLANT_CD INNER JOIN MST_WAREHOUSE w ON z.WAREHOUSE_CD = w.WAREHOUSE_CD LEFT JOIN COM_CODE c ON c.GRP_CD = 'MCS_LOC_STATUS' AND l.LOCATION_STATUS = c.COM_CD
AND z.PLANT_CD = #{plantCd} AND z.WAREHOUSE_CD = #{warehouseCd} AND l.ZONE_ID = #{zoneId} AND l.LOCATION_CD LIKE CONCAT('%', #{locationCd}, '%') AND l.LOCATION_NM LIKE CONCAT('%', #{locationNm}, '%') AND l.LOCATION_STATUS = #{locationStatus}
ORDER BY z.PLANT_CD, z.WAREHOUSE_CD, z.ZONE_CD, l.LOCATION_CD LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM MCS_LOCATION l
INNER JOIN MCS_ZONE z ON l.ZONE_ID = z.ZONE_ID

    AND z.PLANT_CD = #{plantCd}
    AND z.WAREHOUSE_CD = #{warehouseCd}
    AND l.ZONE_ID = #{zoneId}
    AND l.LOCATION_CD LIKE CONCAT('%', #{locationCd}, '%')
    AND l.LOCATION_NM LIKE CONCAT('%', #{locationNm}, '%')
    AND l.LOCATION_STATUS = #{locationStatus}

